// kaleidoscope
//@param segments 3.0 12.0 6.0
fn render(c : Ctx) -> vec3f {
  let q = c.uv - vec2f(0.5);
  var a = atan2(q.y, q.x);
  let r = length(q);
  let seg = 6.2831 / segments();
  a = a - seg * floor(a / seg);
  a = abs(a - seg * 0.5);
  a += c.rawT * 0.05 * c.speed + c.beat * 0.1;
  let k = vec2f(cos(a), sin(a)) * r + vec2f(0.5);
  var col = srcTex(k);
  col = max(col, prevTex(c.uv) * c.fb);
  return col;
}
